<section class="py-5"><div class="container" style="max-width:760px"><div class="card shadow-sm"><div class="card-body p-4 p-lg-5"><h1 class="h3">Request Service</h1><p class="text-muted">Hello <?=e($customer['display_name'])?>. Tell us what date works best. This is a request, not a confirmed appointment, because calendars apparently require diplomacy.</p><form method="post"><?=csrf_field()?><div class="mb-3"><label class="form-label">Property</label><select name="property_id" class="form-select"><?php foreach($properties as $p):?><option value="<?=e($p['id'])?>"><?=e($p['address1'].' '.$p['city'])?></option><?php endforeach?></select></div><div class="mb-3"><label class="form-label">Service</label><select name="service_id" class="form-select"><option value="">Not sure yet</option><?php foreach($services as $s):?><option value="<?=e($s['id'])?>"><?=e($s['name'])?></option><?php endforeach?></select></div><div class="row g-3"><div class="col-md-6"><label class="form-label">Preferred date</label><input type="date" name="preferred_date" min="<?=date('Y-m-d',strtotime('+1 day'))?>" class="form-control" required></div><div class="col-md-6"><label class="form-label">Alternate date</label><input type="date" name="alternate_date" class="form-control"></div></div><div class="my-3"><label class="form-label">Preferred time</label><select name="preferred_window" class="form-select"><option value="any">Any time</option><option value="morning">Morning</option><option value="afternoon">Afternoon</option><option value="evening">Evening</option></select></div><div class="mb-3"><label class="form-label">Details</label><textarea name="notes" rows="4" class="form-control"></textarea></div><button class="btn btn-primary">Submit Request</button></form></div></div></div></section>
